---光效管理器
---@class LBattleViewEffectMgr
local LBattleViewEffectMgr = classX("LBattleViewEffectMgr", nil)

local LBattleViewEffect = require("LApp.gameplay.videobattle.view.obj.LBattleViewEffect")

function LBattleViewEffectMgr:ctor()
    ---@type LBattleViewMgr
    self._viewMgr = nil

    ---@type LBattleViewEffect[]
    self._effectList = {}

    ---@type LBattleViewEffect[]
    self._recordHideEffectList = {}

    self._recordHurtIdMap = {}

    self._preloadList = {}

    self._reqCntList = {}

    self._effectIdx = 0

    self._effTaskIdx = 0
    self._effTaskList ={}
    self._taskPreloadList ={}
    self._loadEndIndex = {}

    --- 正在播放 战斗中仅显示攻击出手者和目标者，其他场景中战斗小人隐藏
    self._showEffectFocus = false
end

function LBattleViewEffectMgr:Initialize()

end

function LBattleViewEffectMgr:ClearAll()
    self:ClearAllEffect()
end

---@param viewMgr LBattleViewMgr
function LBattleViewEffectMgr:SetViewMgr(viewMgr)
    self._viewMgr = viewMgr
    self._effectMgr = viewMgr:GetEffectMgr()
    self._viewFace = viewMgr:GetViewFace()
end

function LBattleViewEffectMgr:SetRootNode(node)
    self._effectRoot = node.transform
end

function LBattleViewEffectMgr:GetRootNode()
    return self._effectRoot
end

function LBattleViewEffectMgr:SetFormationCenter(formationCenter)
    self._formationCenter = formationCenter
end

function LBattleViewEffectMgr:GetFormationCenter()
    return self._formationCenter
end

function LBattleViewEffectMgr:GetFormationCenterPos()
    return self._formationCenter and self._formationCenter.position or Vector3.zero
end
-----------------------------------------------------------------
function LBattleViewEffectMgr:MakeEffectObject(parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,resType)
    local eff = nil
    local curEffList = self._preloadList[effId] or {}
    local idx= nil
    if #curEffList > 0 then
        eff = curEffList[1]
        idx = eff:GetIndex()
        table.remove(curEffList, 1)
        self:SubReqCnt(effId)
    else
        idx = self._effectIdx + 1
        self._effectIdx = idx
        eff = LBattleViewEffect:new(self._viewMgr)
    end

    eff:InitView(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,nil,resType)
    eff:SetBattleSkillEffect(false)
    return eff
end

function LBattleViewEffectMgr:MakeBattleSkillEffectObj(parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,resType)
    ---@type LBattleViewEffect
    local eff = nil
    local curEffList = self._preloadList[effId] or {}
    local idx= nil
    if #curEffList > 0 then
        eff = curEffList[1]
        idx = eff:GetIndex()
        table.remove(curEffList, 1)
        self:SubReqCnt(effId)
    else
        idx = self._effectIdx + 1
        self._effectIdx = idx
        eff = LBattleViewEffect:new(self._viewMgr)
    end

    eff:InitView(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,nil,resType)
    eff:SetBattleSkillEffect(true)
    return eff
end



---@return LBattleViewEffect
function LBattleViewEffectMgr:PreloadEffectObject(parentTrans,effId,resType,noAddReqCnt,effData,targetObj)

    if not noAddReqCnt then
        local reqCnt = self:GetReqCnt(effId) + 1
        local preloadList = self._preloadList[effId] or {}
        local preloadCnt = #preloadList
        if preloadCnt >= reqCnt then
            return
        end

        self:AddReqCnt(effId)
    end

    local idx = self._effectIdx + 1
    self._effectIdx = idx


    --- 预加载 全屏特效
    local effType = effData and effData.effType
    if effType and effType == LSkillEffConst.PLAY_EFF_EFFECT then
        local playNum = tonumber(effData.playNum)
        if playNum == 1 then
            --[[			FireEvent(EventNames.ON_LOAD_BATTLEWND_EFFECT,{
                            preload = true,
                            effId = effId,
                            resType = resType,
                            effData = effData,
                            state = 0,
                        })]]
            return nil,nil,true
        end
    end

    ---@type LBattleViewEffect
    local eff = LBattleViewEffect:new(self._viewMgr)
    eff:SetEffData(effData)
    eff:SetTargetObj(targetObj)
    eff:SetBattleSkillEffect(true)
    local isSuc = eff:PreloadCreate(idx,parentTrans,effId,resType,function (...) self:OnEffPreloaded(...) end)
    self:AddPreload(eff)

    return eff,isSuc
end

---@param eff LBattleViewEffect
function LBattleViewEffectMgr:AddPreload(eff)
    local effId = eff:GetEffId()
    local curEffList = self._preloadList[effId] or {}
    table.insert(curEffList, eff)
    self._preloadList[effId] = curEffList
end

function LBattleViewEffectMgr:AddReqCnt(effId)
    local cnt = self._reqCntList[effId] or 0
    cnt = cnt+1
    self._reqCntList[effId] =cnt

    --printInfoN("addeffid "..effId.."cnt "..cnt)
end

function LBattleViewEffectMgr:SubReqCnt(effId)
    local cnt = self._reqCntList[effId] or 0

    cnt = cnt -1
    cnt = Mathf.Clamp(cnt,0,cnt)
    self._reqCntList[effId] = cnt
    --printInfoN("subeffid "..effId.."cnt "..cnt)
end

function LBattleViewEffectMgr:GetReqCnt(effId)
    return self._reqCntList[effId] or 0
end

-----------------------------------------------------------------
function LBattleViewEffectMgr:AddEffect(effect)
    table.insert(self._effectList,effect)
end

function LBattleViewEffectMgr:RemoveEffect(effect)
    effect.isRemoving = true
end

function LBattleViewEffectMgr:DestroyEffect(effect)
    if not effect then return end
    local removeEff
    for i,v in ipairs(self._effectList) do
        if (v == effect) then
            removeEff = table.remove(self._effectList, i)
            break
        end
    end
    if removeEff then
        removeEff:Dispose()
    end
end
-----------------------------------------------------------------

function LBattleViewEffectMgr:OnUpdate(time, deltaTime)
    local effectList = self._effectList
    local removeIds = {}
    for k ,v in ipairs(effectList) do
        if v.isRemoving or not v:OnUpdate(time, deltaTime) then
            if v:IsLongCache() then
                v.isRemoving = nil
                v:ResetToPreloaded() --重置为预加载完成的状态
                self:AddPreload(v)
            else
                v:Dispose()
            end
            table.insert(removeIds,k)
        end
    end
    for k=#removeIds,1,-1 do
        table.remove(effectList,removeIds[k])
    end
end


-----------------------------------------------------------------
function LBattleViewEffectMgr:ClearAllEffect()
    local effList = self._effectList
    if(effList) then
        for k,v in ipairs(effList) do
            v:Dispose()
        end
    end
    self._effectList = {}

    effList = self._preloadList
    if effList then
        for k,v in pairs(effList) do
            for m,n in ipairs(v) do
                n:Dispose()
            end
        end
    end
    self._preloadList = {}
end

---预加载特效任务

function LBattleViewEffectMgr:PreloadEffList(effTask,atkHero)
    local idx = self._effTaskIdx or 0
    local newIdx = idx+ 1
    self._effTaskIdx = newIdx
    self._effTaskList[newIdx] = effTask
    local effList = effTask.effList
    --local isLongCache = effTask.isLongCache
    local preloadList = {}
    local effTrans = self._viewMgr:GetEffectRootTrans()
    for k,v in ipairs(effList) do
        local effRes = v.effRes --光效名字

        local resType = 1
        if v.effType == LSkillEffConst.PLAY_EFF_DRAWING then
            resType = 2
        end
        local effect,isSuc,isWndEff = self:PreloadEffectObject(effTrans, effRes,resType,true,v,atkHero)
        if effect then
            local effIndex = effect:GetIndex()
            if isSuc then
                preloadList[effIndex] = true
            end
        end

        --print(string.format("refName %s ,resIndex %s,isSuc %s ",effRes,effIndex,isSuc))
    end

    self._taskPreloadList[newIdx] = preloadList
    self:CheckTaskLoadEnd()
end

function LBattleViewEffectMgr:OnEffPreloaded(index)

    --print("preload loaded index "..index)
    local isFind = false
    for k,v in pairs(self._taskPreloadList) do
        if v[index] then
            v[index] = nil
            isFind = true
            break
        end
    end
    if not isFind then
        self._loadEndIndex[index] = true
        return
    end

    self:CheckTaskLoadEnd()
end

function LBattleViewEffectMgr:CheckTaskLoadEnd()
    for k,v in pairs(self._loadEndIndex) do
        for k1,v1 in pairs(self._taskPreloadList) do
            if v1[k] then
                v1[k] = nil
                break
            end
        end
    end

    table.removeall(self._loadEndIndex)


    for k,v in pairs(self._taskPreloadList) do
        if table.isempty(v) then
            local effTask = self._effTaskList[k]
            if effTask and effTask.endFunc then
                effTask.endFunc()
            end
            self._effTaskList[k] = nil
        end
    end
end

function LBattleViewEffectMgr:HidePlayingEffects(recordHurtIdMap,atkObjId)
    self._recordHurtIdMap = recordHurtIdMap
    self._showEffectFocus = true
    local recordHideEffectList = {}
    for k,v in pairs(self._effectList) do
        if not v:GetIsBattleSkill() and v:GetEffectPlayState() and
                not v:CheckIsAtkObjHitEffect(atkObjId) then
            v:SetVisible(false)
            table.insert(recordHideEffectList,v)
        end
    end
    self._recordHideEffectList = recordHideEffectList
end

function LBattleViewEffectMgr:ShowPlayingEffects()
    self._showEffectFocus = false
    self._recordHurtIdMap = {}
    if not self._recordHideEffectList or #self._recordHideEffectList < 1 then return end

    for i,v in ipairs(self._recordHideEffectList) do
        if v:GetEffectPlayState() then
            local isDead = v:CheckTargetObjDead()
            if isDead or v:CheckIsHitShowBuff() then
                v:SetVisible(false)
            else
                v:SetVisible(true)
            end
        end
    end
    self._recordHideEffectList = {}
end

function LBattleViewEffectMgr:CheckIsShowEffectFocus()
    return self._showEffectFocus
end

---@param effect LBattleViewEffect
function LBattleViewEffectMgr:AddRecordHideEffectList(effect)
    if not self._recordHideEffectList then
        self._recordHideEffectList = {}
    end
    table.insert(self._recordHideEffectList,effect)
end

---@param effBattleObj LFightObject
function LBattleViewEffectMgr:CheckIsHurtHero(effBattleObj)
    if not self._recordHurtIdMap then return end
    return self._recordHurtIdMap[effBattleObj:GetId()] ~= nil
end

function LBattleViewEffectMgr:Dispose()
    if self._isDisposed then
        return
    end
    self:ClearAllEffect()
    table.dispose(self)
    self._isDisposed = true
end
-----------------------------------------------------------------
return LBattleViewEffectMgr